import { useState } from "react";
import galleryData from "../data/GaleriaFotos.jsx";
import FlechaAbajo from "../icons/flecha-abajo.svg";

const MasonryGrid = () => {

  const COLUMNAS = 3;
  const FILA_INICIAL = 1;
  const FILAS_POR_CLICK = 2;

  const IMAGENES_INICIALES = COLUMNAS * FILA_INICIAL;
  const IMAGENES_POR_CLICK = COLUMNAS * FILAS_POR_CLICK;

  const [cantidadVisible, setCantidadVisible] = useState(IMAGENES_INICIALES);

  const imagenesMostrar = galleryData.slice(0, cantidadVisible);

  const hayMasImagenes = cantidadVisible < galleryData.length;

  const mostrarMas = () => {
    setCantidadVisible(prev => prev + IMAGENES_POR_CLICK);
  };

  return (
    <div className="flex flex-col items-center">

      {/* GRID */}
      <div className="columns-2 md:columns-3 gap-4 space-y-4">
        {imagenesMostrar.map((img) => (
          <img
            key={img.id}
            src={img.src}
            alt={img.alt}
            className="w-full rounded-xl break-inside-avoid shadow-md hover:scale-[1.02] transition"
          />
        ))}
      </div>

      {/* BOTON */}
      {hayMasImagenes && (
        <button
          onClick={mostrarMas}
          className="mt-6 hover:scale-110 transition animate-bounce"
        >
          <img src={FlechaAbajo} className="w-10 opacity-80" />
        </button>
      )}

    </div>
  );
};

export default MasonryGrid;
